import { Routes, Route } from "react-router-dom";
import "./App.css";
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import Signup from "./components/Signup";
import Login from "./components/Login";
import { useEffect, useState } from "react";
import PrivateRoute from "./components/PrivateRoute";
import Services from "./components/Services";
import ContactUs from "./components/ContactUs";
import Footer from "./components/Footer";
import Error404 from "./components/Error404";
import MyBookings from "./components/MyBookings";
import PaymentSuccess from "./components/PaymentSuccess";

function App() {

    // let isSet=document.cookie.split('; ').filter(row => row.startsWith('token')).map(c => c.split('=')[1])[0];
    const [isLoggedIn, setIsLoggedIn] = useState(null);

    console.log(isLoggedIn);

    // useEffect(() => {
    //     setIsLoggedIn(isSet);
    // }, [isSet]);
    // console.log(object);

        useEffect(() => {
          // Read a specific cookie value
          const myCookieValue = getCookie('myCookieName');
          console.log('Cookie Value:', myCookieValue);
      
          // Set a new cookie with a value and an expiration of 7 days
          setCookie('newCookieName', 'cookieValueHere', 7);
        }, []);
    
    return (
        <div className="  bg-richblack-900 flex flex-col ">
            <Navbar isLoggedIn={isLoggedIn} setIsLoggedIn={setIsLoggedIn} />

            <Routes>
                <Route path="/" element={<Home />} />
                <Route path="/services" element={<Services />} />
                <Route path="/contactus" element={<ContactUs />} />
                <Route path="/login" element={<Login setIsLoggedIn={setIsLoggedIn} />} />
                <Route path="/signup" element={<Signup setIsLoggedIn={setIsLoggedIn} />} />
                <Route path="/mybookings" element={
                    <PrivateRoute isLoggedIn={isLoggedIn}>
                        <MyBookings />
                    </PrivateRoute>
                } />
                <Route path="/paymentsuccess" element={<PaymentSuccess />} />
                <Route path="*" element={<Error404 />} />
            </Routes>

            <Footer />
        </div>
    );
}

export default App;
